code.script:
if (current.state.changes() || current.short_description.changes() || current.description.changes()) {
  var closedStates = ['3','4','7']; // example closed/cancelled values
  if (closedStates.indexOf(String(current.state)) > -1 && !gs.hasRole('change_override')) {
    gs.addErrorMessage('Closed changes cannot be updated without the change_override role.');
    current.setAbortAction(true);
  }
}

var threshold = new GlideDateTime();
threshold.addDaysUTC(-7);
var gr = new GlideRecord('incident');
gr.addQuery('active', true);
gr.addQuery('opened_at', '<=', threshold);
gr.query();
while (gr.next()) {
  gs.print(gr.number + ' opened on ' + gr.getDisplayValue('opened_at'));
}

var gr = new GlideRecord('incident');
gr.addEncodedQuery('active=true^priority=1^opened_atRELATIVEGE@dayofweek@ago@7');
gr.query();
while (gr.next()) {
  gs.print(gr.number + ' - ' + gr.short_description);
}

var ga = new GlideAggregate('cmdb_ci');
ga.addQuery('discovery_source', 'CONTAINS', 'Cloud');
ga.addAggregate('COUNT');
ga.groupBy('discovery_source');
ga.query();
while (ga.next()) {
  gs.print(ga.getDisplayValue('discovery_source') + ' -> ' + ga.getAggregate('COUNT'));
}

var gr = new GlideRecord('cmdb_sam_sw_install');
gr.addNullQuery('software_model');
gr.query();
while (gr.next()) {
  gs.print((gr.display_name || gr.getDisplayValue()) + ' | Device: ' + gr.getDisplayValue('cmdb_ci'));
}
